# Script pour créer le fichier de migration
$sql = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
$files = Get-ChildItem -Path "supabase\migrations" -Filter "*.sql"
if ($files.Count -gt 0) {
    $targetFile = $files[0].FullName
    [System.IO.File]::WriteAllText($targetFile, $sql, [System.Text.Encoding]::UTF8)
    Write-Host "✅ Fichier migration rempli : $targetFile" -ForegroundColor Green
} else {
    Write-Host "❌ Aucun fichier SQL trouvé dans supabase/migrations" -ForegroundColor Red
}
